{{main other|{{#if:{{Has short description}} |<!--Do nothing--> |{{#invoke:Type in location|main|UNESCO World Heritage Site|{{{location|}}}}}}}}}{{#if:{{{child|{{{Child|}}}}}}|<templatestyles src="Infobox/mobileviewfix.css"/>}}
{{Infobox
| child    = {{lc:{{{child|{{{Child|}}}}}}}}
| decat    = yes<!-- remove from tracking category -->
|bodyclass = vcard

|titleclass = category
|titlestyle = font-size:125%;
|title = <includeonly>{{#if:{{{child|{{{Child|}}}}}}||{{{WHS|{{{Name|{{PAGENAMEBASE}}}}}}}}}}</includeonly>

|aboveclass = fn org
|abovestyle = padding:0.2em;background:#87CEEB;font-size:100%;
|above = <includeonly>{{colored link|#000|UNESCO World Heritage Site}}</includeonly>

|imagestyle = border-top:1px #aaa solid;padding-top:0.4em;
|image = {{#invoke:InfoboxImage|InfoboxImage|image={{{Image|{{{image|}}}}}}|size={{{image_size|}}}|upright={{{image_upright|1}}}|alt={{{alt|}}}}}

|caption = {{#if:{{{caption|{{{Caption|{{{imagecaption|}}}}}}}}} |{{{caption|{{{Caption|{{{imagecaption|}}}}}}}}}}}

|image2 = {{#if:{{{map|}}} | {{location map|{{{map|}}}
             | border = infobox | float = center
             | width          = {{if empty|{{{map_size|}}}|{{{mapsize|}}}|{{{map_width|}}} }}
             | default_width  = 220
             | max_width      = 250
             | relief         = {{{relief|}}}
             | label          = {{if empty|{{{label|}}}|{{{name|}}} }}
             | position       = {{if empty|{{{label_position|}}}|none}} <!-- change default to none -->  
             | caption        = {{{map_caption|}}}
             | alt            = {{if empty|{{{map_alt|}}}|Map showing the location of {{{name|}}} }}
             | mark           = {{{mark|}}}
             | marksize       = {{if empty|{{{mark_width|}}}|{{{mark_size|}}}}}
             | coordinates    = {{if empty|{{{coordinates|}}}|{{{coords|}}}}} }}
           | {{#invoke:InfoboxImage|InfoboxImage|image={{{map_image|{{{image_map|}}}}}}|size={{if empty|{{{map_size|}}}|{{{mapsize|}}}|{{{map_width|}}} }}|maxsize=256px|alt={{{map_alt|}}}}}
           }}
|caption2 = {{#if:{{{map|}}} || {{{map_caption|}}} }}

|image3   = {{#invoke:Infobox mapframe|auto|mapframe-coord={{{coordinates|{{{coords|}}}}}}}}
|caption3   = {{#invoke:Infobox mapframe|autocaption|onByDefault={{#if:{{{map|}}}{{{map_image|}}}|no|yes}}}}

|rowclass1 = <includeonly>{{#if:{{{child|{{{Child|}}}}}}|mergedrow|}}</includeonly>
|header1 = <includeonly>{{#if:{{{child|{{{Child|}}}}}}|{{Designation/divbox|WHS}}|}}</includeonly>

|labelstyle = padding-right:0.3em;

|rowclass2 = mergedrow
|label2 = Official&nbsp;name
|data2 = {{{Official_name|{{{official_name|}}}}}}

|rowclass3 = mergedrow
|label3 = [[World Heritage Sites by country|Location]]
|data3 = {{{Location|{{{location|}}}}}}

|rowclass4 = mergedrow
|label4 = Part of
|data4 = {{{Part_of|{{{part_of|}}}}}}

|rowclass5 = mergedrow
|label5 = Includes
|data5 = {{{Includes|{{{includes|}}}}}}

|rowclass6 = mergedrow
|label6 = [[World Heritage Site#Selection criteria|Criteria]]
|class6 = category
|data6 = {{#if: {{{Type|}}} |{{{Type}}}:&nbsp;| }}{{{Criteria|{{{criteria|}}}}}}

|rowclass8 = mergedrow
|label8 = Reference
|data8 = {{#if:{{{ID|}}} |{{#if:{{{Link|}}} |[{{{Link}}} {{{ID}}}] |[https://whc.unesco.org/en/list/{{{ID}}} {{{ID}}}] }} }}

|rowclass10 = mergedrow
|label10 = <span style="font-size:85%;font-weight:normal;">[https://whc.unesco.org/en/list/?search=&search_by_country=&type=&media=&region=&order=region UNESCO region]</span>

|rowclass14 = mergedrow
|label14 = Inscription
|data14 = {{if first display both|{{{Year|{{{year|}}}}}}| (<!--
           -->{{#if:{{{Session|}}}
               | {{{Session}}}
               | {{#ifexpr:{{{Year|{{{year|}}}}}}>1976
                  | {{#ifexpr:{{{Year|{{{year|}}}}}}>2020<!--Not held in 2020 due to COVID-19 pandemic-->
                  | {{#ifexpr:{{{Year|{{{year|}}}}}}>2022<!--Not held in 2022 due to Russian invasion of Ukraine-->
                     | {{ordinal|{{#expr:{{{Year|{{{year|}}}}}}-1978}}}}
                     | {{ordinal|{{#expr:{{{Year|{{{year|}}}}}}-1977}}}}}}
                     | {{ordinal|{{#expr:{{{Year|{{{year|}}}}}}-1976}}}}}}
                  | Unknown}} <!--
           -->}} [[World Heritage Committee|Session]])<!--
      -->}}

|rowclass16 = mergedrow
|label16 = Extensions
|data16 = {{{Extension|{{{extension|}}}}}}

|rowclass18 = mergedrow
|label18 = [[List of World Heritage in Danger|Endangered]]
|data18 = {{{Danger|{{{danger|}}}}}}

|rowclass22 = mergedrow
|label22 = Area
|class22 = category
|data22 = {{{Area|{{{area|}}}}}}

|rowclass24 = mergedrow
|label24 = Buffer&nbsp;zone
|class24 = category
|data24 = {{{Buffer_zone|{{{buffer_zone|}}}}}}

|label26 = Website
|class26 = category
|data26 = {{{Website|{{{website|}}}}}}

|label27 = [[Geographic coordinate system|Coordinates]]
|data27 = {{{coordinates|{{{Coordinates|}}}}}}

| data28 = {{{embedded|{{{Embedded|}}}}}}

| label29     = Public transit access
| data29     = {{{publictransit|}}}

|data30 = {{#if:{{both|{{{locmapin|{{{Locmapin|}}}}}}|{{{coordinates|{{{Coordinates|}}}}}}}}
              | {{Location map
                 |{{{locmapin|{{{Locmapin|Earth}}}}}}
                 |coordinates={{{coordinates|{{{Coordinates|}}}}}}
                 |float=center|relief={{{relief}}}|width={{{map_width|}}}|default_width=250|border=infobox
                 |caption=<div style="line-height:1.2em;"><!--
                        -->{{#if:{{{map_caption|}}}
                            |{{{map_caption}}}
                            |Location of {{{name|{{PAGENAMEBASE}}}}} {{#ifeq:{{{locmapin|{{{Locmapin|Earth}}}}}}|Earth |on Earth. |in {{#invoke:Location map|data|{{{locmapin|{{{Locmapin|Earth}}}}}}|name}}}}<!--
                        -->}}<!--
                       --></div><!--
             -->}}<!--
       -->}}

